local function check_permissions()
    local token = ngx.var.http_authorization
    if not token then
        ngx.exit(ngx.HTTP_unauthorized)
    end

    local pattern = "^Bearer [a-zA-Z0-9_-]+$"
    if not ngx.re.match(token, pattern) then
        ngx.exit(ngx.HTTP_unauthorized)
    end

    -- Assume you have a function to validate the token here
    -- If the token is valid, check roles
    local roles = { "user", "admin" } -- example roles
    local user_role = get_user_role(token) -- replace with your function to fetch user role from validated token

    if not in_array(user_role, roles) and (ngx.var.uri ~= "/api" and ngx.var.uri ~= "/admin") then
        ngx.exit(ngx.HTTP_forbidden)
    end
end

function in_array(needle, haystack)
    for _, value in ipairs(haystack) do
        if needle == value then return true end
    end
    return false
end

